/**
 * Notification model and related types.
 *
 * Architectural constraint: All notification delivery goes through adapters
 * that implement the NotificationAdapter interface. The NotificationService
 * coordinates which adapters to use based on the notification channel.
 */

/**
 * Supported notification channels. Each channel has a corresponding adapter.
 */
export type NotificationChannel = 'email' | 'webhook' | 'in-app';

/**
 * Categories of notifications. Used by adapters to customize formatting
 * and by recipients to manage notification preferences.
 */
export type NotificationType =
  | 'order-confirmation'
  | 'order-status-update'
  | 'user-welcome'
  | 'user-updated'
  | 'system-alert';

/**
 * Payload passed to notification adapters for delivery.
 * Adapters receive this and format it for their specific channel.
 */
export interface NotificationPayload {
  /** Target notification channel */
  channel: NotificationChannel;
  /** Category of this notification */
  notificationType: NotificationType;
  /** Recipient identifier (email address, user ID, webhook URL, etc.) */
  recipient: string;
  /** Notification subject / title */
  subject: string;
  /** Notification body content */
  body: string;
  /** Optional structured metadata for adapter-specific formatting */
  metadata?: Record<string, unknown>;
}

/**
 * Result returned by an adapter after attempting delivery.
 */
export interface NotificationResult {
  /** Whether delivery succeeded */
  success: boolean;
  /** Channel that handled the delivery */
  channel: NotificationChannel;
  /** Adapter-specific message (e.g., error details or confirmation ID) */
  message?: string;
}

/**
 * Persisted notification record, stored after delivery is attempted.
 */
export interface NotificationRecord {
  id: string;
  recipient: string;
  channel: NotificationChannel;
  notificationType: NotificationType;
  subject: string;
  body: string;
  success: boolean;
  sentAt: Date;
}

/**
 * Email notification adapter.
 *
 * Implements the NotificationAdapter interface for the 'email' channel.
 * Currently a stub that records sent emails in memory for testing.
 * Replace the send() implementation with a real email provider (e.g.,
 * SendGrid, SES, SMTP) for production use.
 */

import { Logger } from '../utils/logger.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import type { NotificationAdapter } from './notification.adapter.js';

export interface SentEmail {
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];

  /**
   * Send an email notification.
   * Stub implementation: stores the email in memory instead of sending.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

    const email: SentEmail = {
      to: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      sentAt: new Date(),
    };

    this.sentEmails.push(email);

    return {
      success: true,
      channel: 'email',
      message: `Email delivered to ${payload.recipient}`,
    };
  }

  /**
   * Get all emails sent through this adapter. Useful for testing.
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

