parameters.content:
/**
 * Notification service — coordinates notification delivery in response to events.
 *
 * ARCHITECTURE: Event-driven via EventBus.
 *
 * Flow:
 *   1. Domain services (OrderService, UserService) emit events on the EventBus
 *   2. NotificationService listens for those events
 *   3. For each event, it builds a NotificationPayload and dispatches it
 *      to the appropriate registered adapter based on the channel
 *   4. After delivery, it emits notification:sent or notification:failed events
 *
 * CONSTRAINTS:
 * - All notifications MUST go through EventBus.emit() — no direct calls.
 * - All delivery adapters MUST implement the NotificationAdapter interface.
 * - Register adapters via registerAdapter() before events are emitted.
 * - One adapter per channel; registering a second adapter for the same channel
 *   replaces the first.
 *
 * Depends on:
 * - EventBus (event system) for all inter-service communication
 * - NotificationAdapter implementations for actual delivery
 */

import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
} from '../events/event-types.js';
import type {
  NotificationChannel,
  NotificationPayload,
  NotificationRecord,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter. Useful for testing. */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private records: NotificationRecord[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register a delivery adapter for a notification channel.
   * One adapter per channel — a second registration replaces the first.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Send a notification through the appropriate channel adapter.
   * Emits notification:sent or notification:failed events after delivery.
   */
  async send(payload: NotificationPayload): Promise<NotificationRecord> {
    const adapter = this.adapters.get(payload.channel);

    if (!adapter) {
      const record = this.createRecord(payload, false);
      const errorMsg = `No adapter registered for channel: ${payload.channel}`;
      this.logger.error(errorMsg);
      await this.eventBus.emit({
        type: 'notification:failed',
        notification: record,
        error: errorMsg,
        timestamp: new Date(),
      });
      return record;
    }

    const result = await adapter.send(payload);
    const record = this.createRecord(payload, result.success);

    if (result.success) {
      this.logger.info(`Notification ${record.id} sent via ${payload.channel} to ${payload.recipient}`);
      await this.eventBus.emit({
        type: 'notification:sent',
        notification: record,
        timestamp: new Date(),
      });
    } else {
      this.logger.error(`Notification ${record.id} failed via ${payload.channel}: ${result.message}`);
      await this.eventBus.emit({
        type: 'notification:failed',
        notification: record,
        error: result.message ?? 'Unknown error',
        timestamp: new Date(),
      });
    }

    return record;
  }

  /**
   * Get all notification records.
   */
  getNotifications(): NotificationRecord[] {
    return [...this.records];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): NotificationRecord[] {
    return this.records.filter((r) => r.recipient === recipient);
  }

  /**
   * Get the count of all notification records.
   */
  getNotificationCount(): number {
    return this.records.length;
  }

  /**
   * Clear all notification records. Useful for testing.
   */
  clearNotifications(): void {
    this.records = [];
  }

  /**
   * Register EventBus handlers for domain events.
   * All event subscriptions go through EventBus — no other patterns.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });

    this.eventBus.on<UserCreatedEvent>('user:created', (event) => {
      return this.handleUserCreated(event);
    });
  }

  /**
   * Handle order created — send confirmation email.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.send({
      channel: 'email',
      notificationType: 'order-confirmation',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      metadata: { orderId: event.order.id, userId: event.user.id },
    });
  }

  /**
   * Handle order status change — send update email.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    await this.send({
      channel: 'email',
      notificationType: 'order-status-update',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      metadata: { orderId: event.order.id, previousStatus: event.previousStatus, newStatus: event.newStatus },
    });
  }

  /**
   * Handle user created — send welcome email.
   */
  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    await this.send({
      channel: 'email',
      notificationType: 'user-welcome',
      recipient: event.user.email,
      subject: 'Welcome to TaskFlow Pro',
      body: `Welcome, ${event.user.name}! Your account has been created.`,
      metadata: { userId: event.user.id },
    });
  }

  /**
   * Create and store a notification record.
   */
  private createRecord(payload: NotificationPayload, success: boolean): NotificationRecord {
    const record: NotificationRecord = {
      id: generateNotificationId(),
      recipient: payload.recipient,
      channel: payload.channel,
      notificationType: payload.notificationType,
      subject: payload.subject,
      body: payload.body,
      success,
      sentAt: new Date(),
    };
    this.records.push(record);
    return record;
  }
}

