+/**
+ * Notification model and related types.
+ *
+ * Architectural constraint: All notification delivery goes through adapters
+ * that implement the NotificationAdapter interface. The NotificationService
+ * coordinates which adapters to use based on the notification channel.
+ */
+
+/**
+ * Supported notification channels. Each channel has a corresponding adapter.
+ */
+export type NotificationChannel = 'email' | 'webhook' | 'in-app';
+
+/**
+ * Categories of notifications. Used by adapters to customize formatting
+ * and by recipients to manage notification preferences.
+ */
+export type NotificationType =
+  | 'order-confirmation'
+  | 'order-status-update'
+  | 'user-welcome'
+  | 'user-updated'
+  | 'system-alert';
+
+/**
+ * Payload passed to notification adapters for delivery.
+ * Adapters receive this and format it for their specific channel.
+ */
+export interface NotificationPayload {
+  /** Target notification channel */
+  channel: NotificationChannel;
+  /** Category of this notification */
+  notificationType: NotificationType;
+  /** Recipient identifier (email address, user ID, webhook URL, etc.) */
+  recipient: string;
+  /** Notification subject / title */
+  subject: string;
+  /** Notification body content */
+  body: string;
+  /** Optional structured metadata for adapter-specific formatting */
+  metadata?: Record<string, unknown>;
+}
+
+/**
+ * Result returned by an adapter after attempting delivery.
+ */
+export interface NotificationResult {
+  /** Whether delivery succeeded */
+  success: boolean;
+  /** Channel that handled the delivery */
+  channel: NotificationChannel;
+  /** Adapter-specific message (e.g., error details or confirmation ID) */
+  message?: string;
+}
+
+/**
+ * Persisted notification record, stored after delivery is attempted.
+ */
+export interface NotificationRecord {
+  id: string;
+  recipient: string;
+  channel: NotificationChannel;
+  notificationType: NotificationType;
+  subject: string;
+  body: string;
+  success: boolean;
+  sentAt: Date;
+}

